for path in ['/api/log', '/api/log/bulk', '/api/body-metrics', '/api/tracker/{program_id}/session']:
    if path in d['paths']:
        for method, info in d['paths'][path].items\(\):
            if method == 'post':
                body = info.get\('requestBody', {}\)
                ref = None
                if body:
                    content = body.get\('content', {}\)
                    for ct, schema in content.items\(\):
                        ref = schema.get\('schema', {}\)
                print\(f'{method.upper\(\)} {path}: {json.dumps\(ref, indent=2\)[:500]}'\)
")

